mapper.insert:
insert into public_agent_config_rollouts(
    rollout_id, config_scope, scope_key, branch, commit_hash, previous_commit_hash,
    initiated_by_user_id, initiated_linux_server_id,
    status, trace_id, created_at, updated_at
) values (
    #{rolloutId}, #{scope}, #{scopeKey}, #{branch}, #{expectedCommitHash}, #{previousCommitHash},
    #{initiatedByUserId}, #{initiatedLinuxServerId},
    'PREPARING', #{traceId}, #{now}, #{now}
)

mapper.update:
update public_agent_config_rollouts
set commit_hash = #{commitHash}, updated_at = #{now}
where rollout_id = #{rolloutId} and status = 'PREPARING'

update public_agent_config_rollouts
set status = 'ABORTED', failure_reason = #{reason}, completed_at = #{now}, updated_at = #{now}
where rollout_id = #{rolloutId} and status = 'PREPARING'

update public_agent_config_rollout_memberships
set status = 'DECOMMISSIONED', decommissioned_at = #{now}, updated_at = #{now}
where linux_server_id = #{linuxServerId}

update public_agent_config_rollout_servers s
set status = 'DECOMMISSIONED', lease_until = null, lease_token = null,
    last_error = 'SERVER_DECOMMISSIONED', updated_at = #{now}
where s.linux_server_id = #{linuxServerId}
  and s.status not in ('SYNCED', 'DECOMMISSIONED')
  and exists (
      select 1 from public_agent_config_rollouts r
      where r.rollout_id = s.rollout_id and r.status in ('PREPARING', 'DRAINING')
  )

update public_agent_config_rollout_targets t
set status = 'ABANDONED', lease_until = null, lease_token = null,
    last_error = 'SERVER_DECOMMISSIONED', updated_at = #{now}
where t.linux_server_id = #{linuxServerId}
  and t.status not in ('DISPOSED', 'ABANDONED')
  and exists (
      select 1 from public_agent_config_rollouts r
      where r.rollout_id = t.rollout_id and r.status in ('PREPARING', 'DRAINING')
  )

update public_agent_config_rollout_worktrees
set status = 'ABANDONED', reason = 'SERVER_DECOMMISSIONED',
    lease_until = null, lease_token = null, updated_at = #{now}
where linux_server_id = #{linuxServerId}
  and status not in ('SYNCED', 'ABANDONED')

mapper.insert:
insert into public_agent_config_rollout_targets(
    target_id, rollout_id, user_id, linux_server_id, container_id, port,
    process_pid, process_started_at, base_url,
    status, retry_count, next_retry_at, lease_until, lease_token, created_at, updated_at
) values (
    #{row.targetId}, #{row.rolloutId}, #{row.userId}, #{row.linuxServerId}, #{row.containerId},
    #{row.port}, #{row.processPid}, #{row.processStartedAt}, #{row.baseUrl},
    'RETRY_WAIT', #{row.retryCount}, #{now}, null, null, #{now}, #{now}
) on conflict (rollout_id, linux_server_id, container_id, port) do nothing

mapper.update:
update public_agent_config_rollout_servers
set status = 'PROCESSING', lease_until = #{leaseUntil}, lease_token = #{leaseToken}, updated_at = #{now}
where rollout_id = #{rolloutId} and linux_server_id = #{linuxServerId}
  and ((status in ('PENDING', 'RETRY_WAIT') and next_retry_at <= #{now})
    or (status = 'PROCESSING' and lease_until <= #{now}))

update public_agent_config_rollout_servers
set lease_until = #{leaseUntil}, updated_at = #{now}
where rollout_id = #{rolloutId} and linux_server_id = #{linuxServerId}
  and status = 'PROCESSING' and lease_token = #{leaseToken}

update public_agent_config_rollout_servers
set status = 'SYNCED', synced_at = #{now}, lease_until = null, lease_token = null,
    last_error = null, updated_at = #{now}
where rollout_id = #{rolloutId} and linux_server_id = #{linuxServerId}
  and status = 'PROCESSING' and lease_token = #{leaseToken}

update public_agent_config_rollout_servers
set status = 'RETRY_WAIT', retry_count = #{retryCount}, next_retry_at = #{nextRetryAt},
    lease_until = null, lease_token = null, last_error = #{errorMessage}, updated_at = #{now}
where rollout_id = #{rolloutId} and linux_server_id = #{linuxServerId}
  and status = 'PROCESSING' and lease_token = #{leaseToken}

update public_agent_config_rollout_worktrees
set status = 'PROCESSING', lease_until = #{leaseUntil}, lease_token = #{leaseToken}, updated_at = #{now}
where rollout_id = #{rolloutId} and personal_workspace_id = #{personalWorkspaceId}
  and ((status in ('PENDING', 'AWAITING_USER') and next_retry_at <= #{now})
    or (status = 'PROCESSING' and lease_until <= #{now}))

update public_agent_config_rollout_worktrees
set status = 'AWAITING_USER', reason = #{reason}, retry_count = #{retryCount},
    next_retry_at = #{nextRetryAt}, lease_until = null, lease_token = null, updated_at = #{now}
where rollout_id = #{rolloutId} and personal_workspace_id = #{personalWorkspaceId}
  and status = 'PROCESSING' and lease_token = #{leaseToken}

update public_agent_config_rollout_worktrees
set status = 'SYNCED', reason = null, synced_at = #{now},
    lease_until = null, lease_token = null, updated_at = #{now}
where rollout_id = #{rolloutId} and personal_workspace_id = #{personalWorkspaceId}
  and status = 'PROCESSING' and lease_token = #{leaseToken}

update public_agent_config_rollout_worktrees
set status = 'ABANDONED', reason = #{reason},
    lease_until = null, lease_token = null, updated_at = #{now}
where rollout_id = #{rolloutId} and personal_workspace_id = #{personalWorkspaceId}
  and status = 'PROCESSING' and lease_token = #{leaseToken}

