update public_agent_config_rollout_targets
set status = 'PROCESSING', lease_until = #{leaseUntil}, lease_token = #{leaseToken}, updated_at = #{now}
where target_id = #{targetId}
  and ((status = 'RETRY_WAIT' and next_retry_at <= #{now})
    or (status = 'PROCESSING' and lease_until <= #{now}))

update public_agent_config_rollout_targets
set status = 'RETRY_WAIT', retry_count = #{retryCount}, next_retry_at = #{nextRetryAt},
    lease_until = null, lease_token = null, last_error = #{errorMessage}, updated_at = #{now}
where target_id = #{targetId} and status = 'PROCESSING' and lease_token = #{leaseToken}

update public_agent_config_rollout_targets
set status = 'DISPOSED', disposed_at = #{now}, lease_until = null, lease_token = null,
    last_error = null, updated_at = #{now}
where target_id = #{targetId} and status = 'PROCESSING' and lease_token = #{leaseToken}

update public_agent_config_rollout_targets
set lease_until = #{leaseUntil}, updated_at = #{now}
where target_id = #{targetId} and status = 'PROCESSING' and lease_token = #{leaseToken}
